from math import exp

dados = [
    ([0.35, 0.60, 0.58, 0.0], 0.0),
    ([0.42, 0.65, 0.62, 0.0], 0.0),
    ([0.48, 0.70, 0.68, 0.0], 0.0),
    ([0.58, 0.78, 0.82, 1.0], 1.0),
    ([0.67, 0.84, 0.88, 1.0], 1.0),
    ([0.73, 0.90, 0.93, 1.0], 1.0),
]

def relu(z):
    return max(0.0, z)


def d_relu(z):
    return 1.0 if z > 0 else 0.0


def sigmoid(z):
    return 1.0 / (1.0 + exp(-z))


def prever(x, p):
    z1 = sum(w * xi for w, xi in zip(p["w1"], x)) + p["b1"]
    z2 = sum(w * xi for w, xi in zip(p["w2"], x)) + p["b2"]
    h1 = relu(z1)
    h2 = relu(z2)
    z3 = p["v1"] * h1 + p["v2"] * h2 + p["c"]
    y_hat = sigmoid(z3)
    return y_hat, (z1, z2, h1, h2)


def mse(dados, p):
    total = 0.0
    for x, y in dados:
        y_hat, _ = prever(x, p)
        total += (y_hat - y) ** 2
    return total / len(dados)


def treinar_rede(dados, epochs=4000, lr=0.2):
    p = {
        "w1": [0.2, 0.1, 0.2, 0.1],
        "w2": [0.1, 0.2, 0.1, 0.2],
        "b1": -0.2,
        "b2": -0.2,
        "v1": 0.3,
        "v2": 0.3,
        "c": -0.1,
    }

    for _ in range(epochs):
        for x, y in dados:
            y_hat, (z1, z2, h1, h2) = prever(x, p)
            d_out = 2 * (y_hat - y) * y_hat * (1 - y_hat)
            d_h1 = d_out * p["v1"] * d_relu(z1)
            d_h2 = d_out * p["v2"] * d_relu(z2)

            for i in range(4):
                p["w1"][i] -= lr * d_h1 * x[i]
                p["w2"][i] -= lr * d_h2 * x[i]

            p["b1"] -= lr * d_h1
            p["b2"] -= lr * d_h2
            p["v1"] -= lr * d_out * h1
            p["v2"] -= lr * d_out * h2
            p["c"] -= lr * d_out

    return p


parametros = treinar_rede(dados)
print("MSE final:", round(mse(dados, parametros), 4))

from math import exp

data = [
    ([0.35, 0.60, 0.58, 0.0], 0.0),
    ([0.42, 0.65, 0.62, 0.0], 0.0),
    ([0.48, 0.70, 0.68, 0.0], 0.0),
    ([0.58, 0.78, 0.82, 1.0], 1.0),
    ([0.67, 0.84, 0.88, 1.0], 1.0),
    ([0.73, 0.90, 0.93, 1.0], 1.0),
]

def relu(z):
    return max(0.0, z)


def d_relu(z):
    return 1.0 if z > 0 else 0.0


def sigmoid(z):
    return 1.0 / (1.0 + exp(-z))


def predict(x, p):
    z1 = sum(w * xi for w, xi in zip(p["w1"], x)) + p["b1"]
    z2 = sum(w * xi for w, xi in zip(p["w2"], x)) + p["b2"]
    h1 = relu(z1)
    h2 = relu(z2)
    z3 = p["v1"] * h1 + p["v2"] * h2 + p["c"]
    y_hat = sigmoid(z3)
    return y_hat, (z1, z2, h1, h2)


def mse(data, p):
    total = 0.0
    for x, y in data:
        y_hat, _ = predict(x, p)
        total += (y_hat - y) ** 2
    return total / len(data)


def train_network(data, epochs=4000, lr=0.2):
    p = {
        "w1": [0.2, 0.1, 0.2, 0.1],
        "w2": [0.1, 0.2, 0.1, 0.2],
        "b1": -0.2,
        "b2": -0.2,
        "v1": 0.3,
        "v2": 0.3,
        "c": -0.1,
    }

    for _ in range(epochs):
        for x, y in data:
            y_hat, (z1, z2, h1, h2) = predict(x, p)
            d_out = 2 * (y_hat - y) * y_hat * (1 - y_hat)
            d_h1 = d_out * p["v1"] * d_relu(z1)
            d_h2 = d_out * p["v2"] * d_relu(z2)

            for i in range(4):
                p["w1"][i] -= lr * d_h1 * x[i]
                p["w2"][i] -= lr * d_h2 * x[i]

            p["b1"] -= lr * d_h1
            p["b2"] -= lr * d_h2
            p["v1"] -= lr * d_out * h1
            p["v2"] -= lr * d_out * h2
            p["c"] -= lr * d_out

    return p


params = train_network(data)
print("Final MSE:", round(mse(data, params), 4))
